const user = $input.item.json;
const attrs = user.custom_attributes;

return {
  json: {
    unique_id: user.user_id,
    account_id: user.account,
    inbox_id: user.inbox,
    conversation_id: user.conversation,
    contact_id: user.contact,
    guardian_name: attrs.guardian_name || '',
    guardian_email: user.email || attrs.email || '',
    appointment_child: attrs.appointment_child || '',
    appointment_date: attrs.appointment_date || '',
    appointment_end: attrs.appointment_end || ''
  }
};

const user = $input.item.json;

return {
  json: {
    unique_id: user.user_id,
    account_id: user.account,
    inbox_id: user.inbox,
    conversation_id: user.conversation,
    contact_id: user.contact,
    plan_offer_id: $('Set_UniqueID_Plano').item.json.plan_offer_id
  }
};

